:root {
  --bg: #0d1117;
  --bg-elev: #161b22;
  --bg-card: rgba(22, 27, 34, 0.78);
  --border: rgba(99, 197, 235, 0.16);
  --border-strong: rgba(99, 197, 235, 0.4);
  --text: #e6edf3;
  --muted: #8b949e;
  --react: #61dafb;
  --react-deep: #149eca;
  --accent: #a78bfa;
  --success: #4ade80;
  --warn: #fbbf24;
  --danger: #f87171;
  --code-bg: rgba(1, 4, 9, 0.85);
  --shadow: 0 30px 60px -20px rgba(0, 0, 0, 0.6);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI',
    Roboto, sans-serif;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  padding: 0;
  min-height: 100%;
  background: var(--bg);
  color: var(--text);
  -webkit-font-smoothing: antialiased;
}

body {
  overflow-x: hidden;
  background:
    radial-gradient(900px 500px at 100% 0%, rgba(20, 158, 202, 0.25), transparent 60%),
    radial-gradient(900px 500px at 0% 100%, rgba(167, 139, 250, 0.18), transparent 60%),
    var(--bg);
}

.bg-blobs {
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  overflow: hidden;
}

.bg-blobs span {
  position: absolute;
  width: 540px;
  height: 540px;
  border-radius: 50%;
  filter: blur(110px);
  opacity: 0.4;
  animation: float 18s ease-in-out infinite;
}

.bg-blobs span:nth-child(1) {
  background: var(--react);
  top: -120px;
  left: -120px;
}

.bg-blobs span:nth-child(2) {
  background: var(--accent);
  bottom: -180px;
  right: -120px;
  animation-delay: -6s;
}

.bg-blobs span:nth-child(3) {
  background: var(--react-deep);
  top: 40%;
  left: 50%;
  animation-delay: -12s;
}

@keyframes float {
  0%, 100% { transform: translate(0, 0) scale(1); }
  33%      { transform: translate(40px, -30px) scale(1.05); }
  66%      { transform: translate(-30px, 40px) scale(0.95); }
}

#app {
  position: relative;
  z-index: 1;
  max-width: 1080px;
  margin: 0 auto;
  padding: 56px 24px 80px;
}

.hero {
  text-align: center;
  margin-bottom: 56px;
}

.badge {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 8px 14px;
  border: 1px solid var(--border);
  border-radius: 999px;
  background: rgba(22, 27, 34, 0.7);
  backdrop-filter: blur(8px);
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--muted);
  margin-bottom: 24px;
}

.badge .react-icon {
  width: 14px;
  height: 14px;
  animation: spin 12s linear infinite;
}

@keyframes spin { to { transform: rotate(360deg); } }

h1 {
  font-size: clamp(2rem, 5vw, 3.4rem);
  line-height: 1.1;
  font-weight: 800;
  margin: 0 0 18px;
  letter-spacing: -0.02em;
}

.gradient-text {
  background: linear-gradient(120deg, var(--react) 0%, var(--accent) 100%);
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
}

.lede {
  max-width: 640px;
  margin: 0 auto 28px;
  color: var(--muted);
  font-size: 17px;
  line-height: 1.6;
}

.lede code {
  background: var(--code-bg);
  padding: 2px 6px;
  border-radius: 4px;
  color: var(--react);
  font-size: 14px;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
}

.hero-actions {
  display: flex;
  gap: 12px;
  justify-content: center;
  flex-wrap: wrap;
}

.btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 12px 20px;
  border-radius: 10px;
  border: 1px solid transparent;
  font: inherit;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: transform 0.15s ease, box-shadow 0.15s ease, background 0.15s ease;
  text-decoration: none;
  color: var(--text);
  background: rgba(255, 255, 255, 0.05);
  white-space: nowrap;
}

.btn:hover { transform: translateY(-1px); }
.btn:active { transform: translateY(0); }
.btn:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }

.btn-primary {
  background: linear-gradient(120deg, var(--react-deep), var(--react));
  color: #0d1117;
  box-shadow: 0 12px 30px -10px rgba(20, 158, 202, 0.7);
}

.btn-ghost {
  background: transparent;
  border-color: var(--border-strong);
  color: var(--text);
}

.btn-ghost:hover { background: rgba(255, 255, 255, 0.05); }
.btn-small { padding: 8px 14px; font-size: 13px; }

.grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
  gap: 20px;
}

.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 22px;
  backdrop-filter: blur(12px);
  box-shadow: var(--shadow);
  display: flex;
  flex-direction: column;
  gap: 14px;
  transition: transform 0.2s ease, border-color 0.2s ease;
  position: relative;
  overflow: hidden;
}

.card:hover {
  transform: translateY(-2px);
  border-color: var(--border-strong);
}

.card header { display: flex; flex-direction: column; gap: 8px; }

.tag {
  align-self: flex-start;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  padding: 4px 10px;
  border-radius: 999px;
  background: rgba(99, 197, 235, 0.15);
  color: var(--react);
}

.card h2 { font-size: 17px; margin: 0; font-weight: 700; }
.card p {
  margin: 0;
  color: var(--muted);
  font-size: 14px;
  line-height: 1.55;
}
.card p code {
  background: var(--code-bg);
  padding: 1px 5px;
  border-radius: 3px;
  color: var(--react);
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 12.5px;
}

/* Counter demo */
.counter {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
}

.counter-value {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 34px;
  font-weight: 700;
  color: var(--react);
  min-width: 80px;
  text-align: center;
  font-variant-numeric: tabular-nums;
}

.counter-controls {
  display: flex;
  gap: 6px;
}

.counter-controls .btn-small {
  width: 36px;
  padding: 8px 0;
  justify-content: center;
}

/* Todo demo */
.todo-form {
  display: flex;
  gap: 8px;
}

.todo-input {
  flex: 1;
  background: rgba(1, 4, 9, 0.6);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 8px 12px;
  color: var(--text);
  font: inherit;
  font-size: 14px;
  outline: none;
  transition: border-color 0.15s ease;
}

.todo-input:focus { border-color: var(--react); }

.todo-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
  max-height: 160px;
  overflow-y: auto;
}

.todo-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 6px 8px;
  border-radius: 6px;
  font-size: 14px;
  transition: background 0.15s ease;
}

.todo-item:hover { background: rgba(255, 255, 255, 0.03); }

.todo-item input[type="checkbox"] {
  accent-color: var(--react);
  cursor: pointer;
  width: 16px;
  height: 16px;
  margin: 0;
}

.todo-item.done span { text-decoration: line-through; color: var(--muted); }

.todo-item .remove {
  margin-left: auto;
  background: none;
  border: none;
  color: var(--muted);
  cursor: pointer;
  font-size: 16px;
  line-height: 1;
  padding: 0 4px;
}

.todo-item .remove:hover { color: var(--danger); }

.todo-empty {
  font-size: 13px;
  color: var(--muted);
  text-align: center;
  padding: 16px 0;
  font-style: italic;
}

/* Clock demo */
.clock {
  text-align: center;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 28px;
  font-weight: 700;
  color: var(--accent);
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.04em;
}

.clock-date {
  font-size: 13px;
  font-weight: 400;
  color: var(--muted);
  letter-spacing: 0;
  margin-top: 4px;
}

/* Color demo */
.color-preview {
  height: 56px;
  border-radius: 10px;
  border: 1px solid var(--border);
  transition: background 0.2s ease;
}

.sliders {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.slider-row {
  display: grid;
  grid-template-columns: 20px 1fr 50px;
  align-items: center;
  gap: 10px;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 12px;
}

.slider-row input {
  accent-color: var(--react);
  cursor: pointer;
}

.slider-row .label {
  color: var(--muted);
  font-weight: 700;
}

.slider-row .value {
  color: var(--text);
  text-align: right;
  font-variant-numeric: tabular-nums;
}

/* Fetch demo */
.quote {
  font-style: italic;
  font-size: 15px;
  line-height: 1.55;
  color: var(--text);
  min-height: 60px;
}

.quote-author {
  font-style: normal;
  font-size: 13px;
  color: var(--muted);
  margin-top: 6px;
  font-weight: 600;
}

.quote.loading { color: var(--muted); }

/* Stats / Memo demo */
.stats {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
}

.stat {
  background: rgba(1, 4, 9, 0.5);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 10px 12px;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
}

.stat-label {
  font-size: 10px;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--muted);
  margin-bottom: 4px;
}

.stat-value {
  font-size: 18px;
  font-weight: 700;
  color: var(--react);
  font-variant-numeric: tabular-nums;
}

.section-title {
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--muted);
  margin: 40px 0 16px;
  display: flex;
  align-items: center;
  gap: 12px;
}

.section-title::before, .section-title::after {
  content: '';
  flex: 1;
  height: 1px;
  background: var(--border);
}

.foot {
  text-align: center;
  margin-top: 56px;
  color: var(--muted);
  font-size: 13px;
}

.kbd {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  background: rgba(255, 255, 255, 0.06);
  padding: 2px 6px;
  border-radius: 4px;
  border: 1px solid var(--border);
  font-size: 11.5px;
}

@media (max-width: 640px) {
  #app { padding: 32px 16px 56px; }
  .hero { margin-bottom: 36px; }
  .card { padding: 18px; }
}

import React, { useEffect, useState } from 'react';

// `useEffect` runs side-effects after render. Return a cleanup
// function and React invokes it on unmount or before the next run.
export default function Clock() {
  const [now, setNow] = useState(() => new Date());

  useEffect(() => {
    const id = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(id);
  }, []);

  const time = now.toLocaleTimeString([], { hour12: false });
  const date = now.toLocaleDateString([], {
    weekday: 'long',
    month: 'long',
    day: 'numeric',
  });

  return (
    <article className="card">
      <header>
        <span className="tag">useEffect</span>
        <h2>Live clock</h2>
      </header>
      <p>A timer started in <code>useEffect</code> &mdash; cleanup keeps it from leaking when the component unmounts.</p>
      <div className="clock">
        {time}
        <div className="clock-date">{date}</div>
      </div>
    </article>
  );
}

import React, { useState } from 'react';

const hex = (n) => n.toString(16).padStart(2, '0');

// Controlled inputs: state is the source of truth, the UI just
// renders it. Each slider has its own `onChange` lifting up.
export default function ColorMixer() {
  const [rgb, setRgb] = useState({ r: 99, g: 197, b: 235 });
  const css = `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`;
  const hexCode = `#${hex(rgb.r)}${hex(rgb.g)}${hex(rgb.b)}`;

  const set = (key) => (e) =>
    setRgb((prev) => ({ ...prev, [key]: Number(e.target.value) }));

  return (
    <article className="card">
      <header>
        <span className="tag">controlled inputs</span>
        <h2>Color mixer</h2>
      </header>
      <p>Sliders drive state. State drives the preview. The output is always derived &mdash; no manual sync.</p>
      <div className="color-preview" style={{ background: css }} aria-label={`Preview ${hexCode}`} />
      <div className="sliders">
        {['r', 'g', 'b'].map((k) => (
          <label className="slider-row" key={k}>
            <span className="label">{k.toUpperCase()}</span>
            <input type="range" min="0" max="255" value={rgb[k]} onChange={set(k)} />
            <span className="value">{rgb[k]}</span>
          </label>
        ))}
      </div>
      <p style={{ fontFamily: 'JetBrains Mono, ui-monospace, monospace', fontSize: 12 }}>{hexCode}</p>
    </article>
  );
}

import React, { useState } from 'react';

// `useState` returns a value and a setter. Every call to the setter
// triggers a re-render with the new value.
export default function Counter() {
  const [count, setCount] = useState(0);

  return (
    <article className="card">
      <header>
        <span className="tag">useState</span>
        <h2>Counter</h2>
      </header>
      <p>The classic hello-world for state. Click the buttons &mdash; React re-renders only this card.</p>
      <div className="counter">
        <div className="counter-value">{count}</div>
        <div className="counter-controls">
          <button className="btn btn-small btn-ghost" onClick={() => setCount((c) => c - 1)} aria-label="decrement">&minus;</button>
          <button className="btn btn-small btn-ghost" onClick={() => setCount(0)} aria-label="reset">0</button>
          <button className="btn btn-small" onClick={() => setCount((c) => c + 1)} aria-label="increment">+</button>
        </div>
      </div>
    </article>
  );
}

import React, { useMemo, useState } from 'react';

// `useMemo` caches an expensive computation between renders. Here we
// run a deliberately slow primality check so you can feel the cache
// kick in.
function isPrime(n) {
  if (n < 2) return false;
  for (let i = 2; i * i <= n; i++) if (n % i === 0) return false;
  return true;
}

function countPrimes(limit) {
  const t0 = performance.now();
  let total = 0;
  for (let i = 2; i <= limit; i++) if (isPrime(i)) total++;
  return { total, ms: performance.now() - t0 };
}

export default function Memo() {
  const [limit, setLimit] = useState(20000);
  const [unrelated, setUnrelated] = useState(0);

  // Only recomputed when `limit` changes. Bumping `unrelated`
  // re-renders the component but reuses the cached result — the
  // shown cost stays the same until you move the slider.
  const cached = useMemo(() => countPrimes(limit), [limit]);

  return (
    <article className="card">
      <header>
        <span className="tag">useMemo</span>
        <h2>Cache expensive work</h2>
      </header>
      <p>Counting primes up to <code>{limit.toLocaleString()}</code>. The memoized cost shown below only updates when N changes — the render counter doesn&rsquo;t trigger another count.</p>
      <div className="stats">
        <div className="stat">
          <div className="stat-label">π(n)</div>
          <div className="stat-value">{cached.total.toLocaleString()}</div>
        </div>
        <div className="stat">
          <div className="stat-label">Last compute</div>
          <div className="stat-value">{cached.ms.toFixed(1)} ms</div>
        </div>
      </div>
      <div className="sliders">
        <label className="slider-row">
          <span className="label">N</span>
          <input
            type="range"
            min="1000"
            max="100000"
            step="1000"
            value={limit}
            onChange={(e) => setLimit(Number(e.target.value))}
          />
          <span className="value">{(limit / 1000).toFixed(0)}k</span>
        </label>
      </div>
      <button className="btn btn-small btn-ghost" onClick={() => setUnrelated((x) => x + 1)}>
        Re-render without changing N ({unrelated})
      </button>
    </article>
  );
}

import React, { useEffect, useState, useCallback } from 'react';

// A tiny library of quotes from people who shaped computing.
// Swap this for a real `fetch(...)` to talk to your API.
const QUOTES = [
  { text: 'Programs must be written for people to read, and only incidentally for machines to execute.', author: 'Harold Abelson' },
  { text: 'The best way to predict the future is to invent it.', author: 'Alan Kay' },
  { text: 'Simplicity is prerequisite for reliability.', author: 'Edsger W. Dijkstra' },
  { text: 'Premature optimization is the root of all evil.', author: 'Donald Knuth' },
  { text: 'Talk is cheap. Show me the code.', author: 'Linus Torvalds' },
  { text: 'Walking on water and developing software from a specification are easy if both are frozen.', author: 'Edward V. Berard' },
];

// A fake async fetch so the demo works offline. setTimeout simulates
// network latency; replace with a real `fetch(url)` in your project.
const fakeFetch = () =>
  new Promise((resolve) => {
    setTimeout(() => {
      resolve(QUOTES[Math.floor(Math.random() * QUOTES.length)]);
    }, 400);
  });

export default function Quote() {
  const [quote, setQuote] = useState(null);
  const [loading, setLoading] = useState(false);

  const load = useCallback(async () => {
    setLoading(true);
    setQuote(await fakeFetch());
    setLoading(false);
  }, []);

  useEffect(() => { load(); }, [load]);

  return (
    <article className="card">
      <header>
        <span className="tag">async data</span>
        <h2>Quote of the moment</h2>
      </header>
      <p>An async load wrapped in <code>useEffect</code> &mdash; the same pattern works for any fetch.</p>
      <blockquote className={`quote ${loading ? 'loading' : ''}`}>
        {loading
          ? 'Loading…'
          : quote && (
              <>
                &ldquo;{quote.text}&rdquo;
                <div className="quote-author">&mdash; {quote.author}</div>
              </>
            )}
      </blockquote>
      <button className="btn btn-small btn-ghost" onClick={load} disabled={loading}>
        Get another
      </button>
    </article>
  );
}

import React, { useState } from 'react';

const SEED = [
  { id: 1, text: 'Read a hook',     done: true  },
  { id: 2, text: 'Add a component', done: false },
  { id: 3, text: 'Ship it',         done: false },
];

// useState with an array value. Always replace the array (no in-place
// mutation) so React sees a new reference and re-renders.
export default function Todos() {
  const [items, setItems] = useState(SEED);
  const [draft, setDraft] = useState('');

  const add = (e) => {
    e.preventDefault();
    const text = draft.trim();
    if (!text) return;
    setItems((xs) => [...xs, { id: Date.now(), text, done: false }]);
    setDraft('');
  };

  const toggle = (id) =>
    setItems((xs) => xs.map((x) => (x.id === id ? { ...x, done: !x.done } : x)));

  const remove = (id) =>
    setItems((xs) => xs.filter((x) => x.id !== id));

  const remaining = items.filter((x) => !x.done).length;

  return (
    <article className="card">
      <header>
        <span className="tag">arrays in state</span>
        <h2>Todos &mdash; {remaining} left</h2>
      </header>
      <p>Add, toggle, delete. Every update returns a new array so React can diff cheaply.</p>
      <form className="todo-form" onSubmit={add}>
        <input
          className="todo-input"
          value={draft}
          onChange={(e) => setDraft(e.target.value)}
          placeholder="Add a task…"
          aria-label="New task"
        />
        <button className="btn btn-small" type="submit" disabled={!draft.trim()}>Add</button>
      </form>
      <ul className="todo-list">
        {items.length === 0 ? (
          <li className="todo-empty">Inbox zero. Add something.</li>
        ) : (
          items.map((item) => (
            <li key={item.id} className={`todo-item ${item.done ? 'done' : ''}`}>
              <input
                type="checkbox"
                checked={item.done}
                onChange={() => toggle(item.id)}
                aria-label={`Mark ${item.text}`}
              />
              <span>{item.text}</span>
              <button className="remove" onClick={() => remove(item.id)} aria-label="Remove">&times;</button>
            </li>
          ))
        )}
      </ul>
    </article>
  );
}

